const App = () => {
  const names = 'Half Stack application development'
  const part1 = 'Fundamentals of React'
  const exercises1 = 10
  const part2 = 'Using props tco pass data'
  const exercises2 = 7
  const part3 = 'State of a component'
  const exercises3 = 14
  return (
    <div>
      <Header test={names} />
      <Content parts={part1} exerciseFirst={exercises1} />
      <Content parts={part2} exerciseFirst={exercises2} />
      <Content parts={part3} exerciseFirst={exercises3} />
    </div>
  )
}

const Header = (props) => {
  return (
    <h1>{props.test}</h1>
  )
}


const Content = (props) => {
  return (
    <p>{props.parts} {props.exerciseFirst}</p>
  )

}
const Total = (props) => {
  return (
    <p>Number of exercises {exercises1 + exercises2 + exercises3}</p>
  )
}

export default App
